package com.hospital.management.controller.medical;import com.hospital.management.model.*;import com.hospital.management.service.*;import com.hospital.management.service.impl.MedicalRecordServiceImpl;import javax.servlet.*;import javax.servlet.annotation.WebServlet;import javax.servlet.http.*;import java.io.IOException;
@WebServlet("/medical-records")public class MedicalRecordListServlet extends HttpServlet {private final MedicalRecordService service;public MedicalRecordListServlet(){this(new MedicalRecordServiceImpl());}public MedicalRecordListServlet(MedicalRecordService s){service=s;}protected void doGet(HttpServletRequest q,HttpServletResponse r)throws ServletException,IOException{int page=Math.max(1,MedicalRequest.number(q.getParameter("page"),1)),size=Math.min(100,Math.max(1,MedicalRequest.number(q.getParameter("size"),10)));q.setAttribute("recordPage",service.listRecords(new PageRequest(page,size,q.getParameter("search")),MedicalRequest.id(q.getParameter("patientId")),MedicalRequest.id(q.getParameter("doctorId")),MedicalRequest.id(q.getParameter("departmentId")),MedicalRequest.date(q.getParameter("dateFrom")),MedicalRequest.date(q.getParameter("dateTo")),MedicalRequest.user(q)));q.setAttribute("message",q.getParameter("message"));q.setAttribute("error",q.getParameter("error"));q.getRequestDispatcher("/WEB-INF/views/medical-records/list.jsp").forward(q,r);}}
